import React, { useState, useEffect } from 'react';
import api from '../services/api';
import { toast } from 'react-toastify';

const LoanApprovals = () => {
  const [loans, setLoans] = useState([]);
  const [selected, setSelected] = useState(null);
  const [remarks, setRemarks] = useState('');
  const [loading, setLoading] = useState(true);
  const [processing, setProcessing] = useState(false);

  useEffect(() => {
    fetchLoans();
  }, []);

  const fetchLoans = async () => {
    try {
      setLoading(true);
      const res = await api.get('/admin/loans/pending');
      // Handle both wrapped and unwrapped responses
      const loansData = res.data?.data || res.data || [];
      setLoans(Array.isArray(loansData) ? loansData : []);
    } catch (err) {
      console.error(err);
      toast.error('Failed to fetch pending loans');
    } finally {
      setLoading(false);
    }
  };

  const approve = async (id) => {
    setProcessing(true);
    try {
      await api.post(`/admin/loan/${id}/approve`, { remarks });
      toast.success('Loan approved successfully!');
      setLoans(l => l.filter(x => x._id !== id));
      setSelected(null);
      setRemarks('');
    } catch (err) {
      toast.error(err.response?.data?.message || 'Failed to approve loan');
    } finally {
      setProcessing(false);
    }
  }

  const reject = async (id) => {
    if (!remarks.trim()) {
      toast.warning('Please provide a reason for rejection');
      return;
    }
    setProcessing(true);
    try {
      await api.post(`/admin/loan/${id}/reject`, { remarks });
      toast.success('Loan rejected');
      setLoans(l => l.filter(x => x._id !== id));
      setSelected(null);
      setRemarks('');
    } catch (err) {
      toast.error(err.response?.data?.message || 'Failed to reject loan');
    } finally {
      setProcessing(false);
    }
  }

  return (
    <div className="fade-in">
      <div className="flex-between mb-6">
        <div>
          <h2 className="page-title" style={{ marginBottom: '0.5rem' }}>💸 Loan Approvals</h2>
          <p style={{ color: 'var(--text-secondary)', fontSize: '0.875rem', margin: 0 }}>
            Review and approve pending loan requests
          </p>
        </div>
        <div style={{
          display: 'flex',
          alignItems: 'center',
          gap: '1rem',
          padding: '0.75rem 1.25rem',
          background: 'var(--bg-card)',
          borderRadius: '0.75rem',
          border: '1px solid var(--border-bright)'
        }}>
          <span style={{ fontSize: '1.25rem' }}>⏳</span>
          <div>
            <div style={{ fontSize: '0.75rem', color: 'var(--text-secondary)' }}>Pending Requests</div>
            <div style={{ fontSize: '1.25rem', fontWeight: 700, color: 'var(--warning)' }}>
              {loans.length}
            </div>
          </div>
        </div>
      </div>

      <div className="table-container">
        {loading ? (
          <div className="loading-container">
            <div className="loading-spinner"></div>
            <div style={{ color: 'var(--text-secondary)', marginTop: '1rem' }}>Loading pending loans...</div>
          </div>
        ) : loans.length === 0 ? (
          <div style={{ padding: '4rem', textAlign: 'center', color: 'var(--text-secondary)' }}>
            <div style={{ fontSize: '3rem', marginBottom: '1rem' }}>✅</div>
            <div style={{ fontSize: '1.125rem', fontWeight: 500, color: 'var(--text-primary)' }}>All caught up!</div>
            <div style={{ marginTop: '0.5rem' }}>No pending loan requests at the moment.</div>
          </div>
        ) : (
          <table>
            <thead>
              <tr>
                <th>Member</th>
                <th>Amount</th>
                <th>Purpose</th>
                <th>Requested</th>
                <th>Status</th>
                <th>Actions</th>
              </tr>
            </thead>
            <tbody>
              {loans.map(loan => (
                <tr key={loan._id}>
                  <td style={{ fontWeight: 500, color: 'var(--text-primary)' }}>
                    {loan.memberId?.fullName || 'N/A'}
                  </td>
                  <td style={{ color: 'var(--success)', fontWeight: 600 }}>
                    ${loan.amount?.toLocaleString()}
                  </td>
                  <td style={{ color: 'var(--text-secondary)', maxWidth: '200px' }}>
                    {loan.purpose || '-'}
                  </td>
                  <td style={{ color: 'var(--text-secondary)' }}>
                    {new Date(loan.requestDate).toLocaleDateString()}
                  </td>
                  <td>
                    <span className="status-badge status-pending">{loan.status}</span>
                  </td>
                  <td>
                    <button
                      className="btn btn-primary"
                      style={{ padding: '0.5rem 1rem', fontSize: '0.75rem' }}
                      onClick={() => setSelected(loan)}
                    >
                      Review
                    </button>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        )}
      </div>

      {selected && (
        <div className="modal-overlay" onClick={() => !processing && setSelected(null)}>
          <div className="modal-content fade-in" onClick={(e) => e.stopPropagation()} style={{ maxWidth: '600px' }}>
            <div className="flex-between mb-4">
              <div>
                <h3 style={{ margin: 0, fontSize: '1.25rem', color: 'var(--text-primary)' }}>
                  📋 Review Loan Application
                </h3>
                <p style={{ margin: '0.5rem 0 0 0', fontSize: '0.875rem', color: 'var(--text-secondary)' }}>
                  Carefully review the loan details before making a decision
                </p>
              </div>
              <button
                onClick={() => !processing && setSelected(null)}
                className="icon-button"
                disabled={processing}
                style={{ width: '32px', height: '32px' }}
              >
                <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2">
                  <line x1="18" y1="6" x2="6" y2="18" />
                  <line x1="6" y1="6" x2="18" y2="18" />
                </svg>
              </button>
            </div>

            <div style={{
              background: 'var(--bg-hover)',
              padding: '1.5rem',
              borderRadius: '0.75rem',
              border: '1px solid var(--border)',
              marginBottom: '1.5rem'
            }}>
              <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '1.5rem', marginBottom: '1rem' }}>
                <div>
                  <label style={{ fontSize: '0.75rem', color: 'var(--text-secondary)', display: 'block', marginBottom: '0.5rem', textTransform: 'uppercase', letterSpacing: '0.05em' }}>
                    Member Name
                  </label>
                  <div style={{ fontSize: '1rem', fontWeight: '600', color: 'var(--text-primary)' }}>
                    {selected.memberId?.fullName || 'N/A'}
                  </div>
                </div>
                <div>
                  <label style={{ fontSize: '0.75rem', color: 'var(--text-secondary)', display: 'block', marginBottom: '0.5rem', textTransform: 'uppercase', letterSpacing: '0.05em' }}>
                    Amount Requested
                  </label>
                  <div style={{ fontSize: '1.5rem', fontWeight: '700', color: 'var(--success)' }}>
                    ${selected.amount?.toLocaleString()}
                  </div>
                </div>
              </div>
              <div>
                <label style={{ fontSize: '0.75rem', color: 'var(--text-secondary)', display: 'block', marginBottom: '0.5rem', textTransform: 'uppercase', letterSpacing: '0.05em' }}>
                  Purpose
                </label>
                <div style={{
                  fontSize: '0.875rem',
                  color: 'var(--text-primary)',
                  background: 'var(--bg-card)',
                  padding: '0.75rem',
                  borderRadius: '0.5rem',
                  border: '1px solid var(--border)'
                }}>
                  {selected.purpose || 'No purpose provided'}
                </div>
              </div>
            </div>

            <div style={{ marginBottom: '1.5rem' }}>
              <label style={{
                fontSize: '0.875rem',
                fontWeight: '500',
                display: 'block',
                marginBottom: '0.5rem',
                color: 'var(--text-primary)'
              }}>
                Admin Remarks {!remarks.trim() && <span style={{ color: 'var(--danger)' }}>*</span>}
              </label>
              <textarea
                className="input"
                value={remarks}
                onChange={e => setRemarks(e.target.value)}
                placeholder="Enter reason for approval or rejection..."
                style={{
                  height: '100px',
                  width: '100%',
                  resize: 'vertical',
                  fontFamily: 'inherit'
                }}
              />
            </div>

            <div style={{ display: 'flex', gap: '1rem', justifyContent: 'flex-end' }}>
              <button
                className="btn btn-danger"
                onClick={() => reject(selected._id)}
                disabled={processing}
                style={{ display: 'flex', alignItems: 'center', gap: '0.5rem' }}
              >
                {processing ? (
                  <>
                    <div className="loading-spinner" style={{ width: '14px', height: '14px', borderWidth: '2px' }}></div>
                    Processing...
                  </>
                ) : (
                  <>
                    <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2">
                      <line x1="18" y1="6" x2="6" y2="18" />
                      <line x1="6" y1="6" x2="18" y2="18" />
                    </svg>
                    Reject
                  </>
                )}
              </button>
              <button
                className="btn btn-primary"
                onClick={() => approve(selected._id)}
                disabled={processing}
                style={{
                  background: 'var(--success)',
                  display: 'flex',
                  alignItems: 'center',
                  gap: '0.5rem'
                }}
              >
                {processing ? (
                  <>
                    <div className="loading-spinner" style={{ width: '14px', height: '14px', borderWidth: '2px' }}></div>
                    Processing...
                  </>
                ) : (
                  <>
                    <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2">
                      <path d="M20 6L9 17l-5-5" />
                    </svg>
                    Approve
                  </>
                )}
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}
export default LoanApprovals;
